            // Act
            await comp.Find("input").InputAsync("Al");
            timeProvider.Advance(TimeSpan.FromMilliseconds(autocomplete.DebounceInterval));

            // Assert
            await comp.WaitForAssertionAsync(() =>
            {
                debouncedText.Should().Be("Al");
                eventCallbackCount.Should().Be(1);
            });
        }

